mapper.insert:
insert into biz_order (
    order_no, title, description, category, reward_amount, location_text,
    creator_id, status, version, del_flag, create_by, create_time, remark
) values (
    #{orderNo}, #{title}, #{description}, #{category}, #{rewardAmount}, #{locationText},
    #{creatorId}, #{status}, #{version}, '0', #{createBy}, sysdate(), #{remark}
)

insert into biz_order_log (
    order_id, from_status, to_status, operator_id, operator_type, remark, create_time
) values (
    #{orderId}, #{fromStatus}, #{toStatus}, #{operatorId}, #{operatorType}, #{remark}, sysdate()
)
